Manag$$, $$4a8a489c101d8be5e92f6c88a2b9cbca035a685be78777d552af92fb14ec81bc$$, $${"A": "b8f6d282136ad5441194b54de2bb06f9842850731841480051c33eb947503824", "C": "fd366a0f99df8ac10d7361ef3a0ed43dbd6a99f74f4f3a1203f5c623bf4afecc", "D": "d9ed54f4a61c74aa22d0c529fee1af2b67806f690782b010dd4d232b0fe7a989"}$$::jsonb, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$, 1213, $$2026-05-10T04:04:19.242458+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0604558N$$, 2027, $$FY 2027 funding provides for the continued execution of Virginia Class Submarine Undersea Dominance Payload Integration (UDPI) (i.e., Advanced Payloads),
Advanced Acoustic Sensors, and future Blocks concept designs. FY 2027 continues the detailed design of Virginia Class Block VI technical baseline established efforts,
preliminary design for Virginia Class Block VII, and initial concept design studies for Block VIII. Funds will be executed at the Virginia Class design yard and numerous
sub-vendors and warfare centers designing and developing critical, complex ship components necessary for integrating advanced Block VI capabilities into the baseline
class design.

The U.S. Navy must maintain a submarine fleet that is of sufficient capability and numbers to defend American interests. The VIRGINIA Class Submarine, formerly
the New Attack Submarine (New SSN), is being designed to fulfill this need. It will counter potential threats in a multi- mission capable submarine that has the ability
to provide covert, sustained combat presence in denied waters. The primary goal of the program is to develop an affordable yet capable submarine by evaluating a
broad range of system and technology alternatives, and pursuing significant capability and improved performance enhancements while managing technical risk. This
Program Element (PE) provides the technology, prototype components, and systems engineering needed to design and construct the VIRGINIA Class Submarine
and build its Hull, Mechanical and Electrical (HM&E) systems and Command, Control, Communications, and Intelligence (C3I) System. This PE directly supports the
following VIRGINIA Class Submarine missions: (1) covert strike warfare (STRIKE); (2) anti-submarine warfare (ASW); (3) covert intelligence collection/surveillance
(ISR), indication and warning (I&W), and electronic warfare (EW); (4) anti-surface ship warfare (ASUW); (5) special warfare; (6) covert mine warfare; and (7) battle group
support.
Development & Demonstration (SDD)$$, $$This FY 2026 RDT&E Congressional add supports Secure Mobile Initial Outfitting and Portable Underwater Communication Systems (PUCS) for VIRGINIA Class
Submarines.

Secure Mobile Initial Outfitting provides secure modern mobile devices as well as mobile applications to improve the enhance sailor shipboard effectiveness. This FY
2026 funding will accelerate the initial mobile shipset outfitting of submarines and their sailors to enhance their efficiency.

FY 2026 funds will also support the completion of development, test and evaluation and production of PUCS with the goal of providing a system that will increase tactical
