INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0306250M$$, 2027, $$Marine Corps Forces Cyberspace Command (MARFORCYBER) provides advanced cyber warfare capabilities in direct support of US Cyber Command
(USCYBERCOM), Marine Corps Commanders, and national agencies to enable and accomplish global operations. Activities within the project deliver cyberspace
superiority capabilities through the research, development, testing, evaluation, and integration of cyber technologies. The project enables Commanders to disrupt,
deny, degrade, or destroy targets. Research and develop software constructed cyber weapons disrupt rising advanced peer and near-peer threats, as well as violent
extremist organizations seeking to do harm to the United States. The software constructed cyber weapons are target specific and require high quality, rapid adjustments
to achieve desired effects at acceptable levels of risk. The specific details and aspects of these cyber activities are held at a higher classification level.

Adversarial Cyber Developmental Test and Evaluation: Provides mission based cyber risk assessment services to Marine Corps Systems Command (MCSC) programs
of record (PoRs) via Marine Corps Tactical Systems Support Activity (MCTSSA). MCTSSA serves as the Cyber Developmental Test and Evaluation agent in accordance
with DoDI 8500.01, DoDI 5000.02, and the DoD Cybersecurity Test and Evaluation Guidebook. MCTSSA conducts adversarial cyber assessments on programs of
